-- ============================================================
-- Seed: equipo (10) + clientes (72) + prospects (225) + pendings (1008)
-- Idempotente con ON CONFLICT.
-- ============================================================

-- Equipo
on conflict (id) do update set username=excluded.username, password=excluded.password, perms=excluded.perms, name=excluded.name, role=excluded.role, units=excluded.units, color=excluded.color;

-- Clientes MaximUs (72)
on conflict (id) do update set cliente=excluded.cliente, contacto=excluded.contacto, a_cargo=excluded.a_cargo, pais=excluded.pais, servicio=excluded.servicio, empresa_nuestra=excluded.empresa_nuestra, anio_cliente=excluded.anio_cliente, trabajos_medida=excluded.trabajos_medida, portafolios_modelo=excluded.portafolios_modelo, uso_maximus_texto=excluded.uso_maximus_texto, nivel_uso_resumen=excluded.nivel_uso_resumen, pct_maximus=excluded.pct_maximus, accion=excluded.accion, pedidos_total=excluded.pedidos_total, pedidos_90d=excluded.pedidos_90d, pedidos_180d=excluded.pedidos_180d, ultimo_pedido=excluded.ultimo_pedido, dias_sin_pedido=excluded.dias_sin_pedido, max_users_count=excluded.max_users_count, max_logins_total=excluded.max_logins_total, max_logins_ytd=excluded.max_logins_ytd, max_prom_logins_6m=excluded.max_prom_logins_6m, max_propuestas=excluded.max_propuestas, max_portafolios_analizados=excluded.max_portafolios_analizados, max_comparativos=excluded.max_comparativos, max_estrategias=excluded.max_estrategias, max_ultimo_login=excluded.max_ultimo_login, dias_sin_login=excluded.dias_sin_login, score=excluded.score, ped_pct=excluded.ped_pct, max_pct=excluded.max_pct, canal_dominante=excluded.canal_dominante, semaforo=excluded.semaforo;

-- Prospects (225)
on conflict (id) do update set empresa=excluded.empresa, contacto=excluded.contacto, producto=excluded.producto, notas=excluded.notas, prox_seguimiento=excluded.prox_seguimiento, estado=excluded.estado, cliente_compartido=excluded.cliente_compartido;

-- Pendings Consultora (1008)
on conflict (id) do update set cliente=excluded.cliente, descripcion=excluded.descripcion, analista_id=excluded.analista_id, a_cargo=excluded.a_cargo, prioridad=excluded.prioridad, deadline=excluded.deadline, estado=excluded.estado, completed_at=excluded.completed_at, comentarios=excluded.comentarios;
